# Scan e verificação
nm.scan('192.168.1.1,192.168.1.100', '80')

if nm.has_host('192.168.1.1'):
    print('Host 192.168.1.1 encontrado')
else:
    print('Host 192.168.1.1 não encontrado')

if nm.has_host('192.168.1.200'):
    print('Host 192.168.1.200 encontrado')
else:
    print('Host 192.168.1.200 não encontrado')

# Iteração segura
hosts_para_verificar = ['192.168.1.1', '192.168.1.2', '192.168.1.3']
for host in hosts_para_verificar:
    if nm.has_host(host):
        print(f'{host}: {nm[host].state()}')
    else:
        print(f'{host}: não escaneado')

# Antes de acessar dados
if nm.has_host('192.168.1.1'):
    print(f'Portas: {nm["192.168.1.1"].all_tcp()}')

# Verificar após scan com rede
nm.scan('192.168.1.0/24', arguments='-sn')
print(f'Hosts encontrados: {len(nm.all_hosts())}')
print(f'Host específico existe: {nm.has_host("192.168.1.50")}')

# Tentar importar sem nmap
try:
    import nmap
    nm = nmap.PortScanner()
except nmap.PortScannerError as e:
    print(f'Erro: {e}')
    print('Certifique-se que o Nmap está instalado: sudo apt install nmap')

# Scan com argumentos inválidos
try:
    nm.scan('192.168.1.1', arguments='-argumento-invalido')
except nmap.PortScannerError as e:
    print(f'Erro no scan: {e}')

# Host inválido
try:
    nm.scan('host.inexistente.com', '80')
except Exception as e:
    print(f'Erro ao escanear host: {e}')

# Permissão insuficiente (requer sudo)
try:
    nm.scan('192.168.1.1', arguments='-sS -p 80')  # SYN scan requer root
except nmap.PortScannerError as e:
    print(f'Erro de permissão: {e}')
    print('Execute com sudo para scans SYN')

# Timeout
try:
    nm.scan('192.168.1.1', arguments='-p 80', timeout=1)
except Exception as e:
    print(f'Timeout ou erro: {e}')

# Tentar acessar host não escaneado
nm.scan('192.168.1.1', '80')
try:
    host = nm['192.168.1.100']
except KeyError as e:
    print(f'Erro: Host {e} não encontrado nos resultados')

