from tqdm import trange
import time

# Uso básico
for i in trange(100):
    time.sleep(0.01)

# Com descrição
for i in trange(100, desc='Loop com trange'):
    time.sleep(0.01)

# Com unidade
for i in trange(500, unit='passos', desc='Processando'):
    time.sleep(0.005)

# Com intervalo
for i in trange(10, 100, 5, desc='Range com step'):
    time.sleep(0.05)

# Com leave=False
for i in trange(50, leave=False, desc='Temporário'):
    time.sleep(0.02)

# Aninhado com tqdm
for i in trange(3, desc='Externo'):
    for j in trange(100, desc='Interno', leave=False):
        time.sleep(0.001)

# Com posição
for i in trange(100, position=0, desc='Principal'):
    time.sleep(0.01)

# Com barra colorida
for i in trange(100, colour='magenta', desc='Rosa'):
    time.sleep(0.01)

from tqdm import tqdm
import time

# Tratamento automático de Ctrl+C
print('Pressione Ctrl+C para interromper')
try:
    for i in tqdm(range(1000), desc='Interrompível'):
        time.sleep(0.01)
except KeyboardInterrupt:
    print('\nOperação interrompida pelo usuário')

# Com cleanup manual
pbar = tqdm(range(500), desc='Manual interrupt')
try:
    for i in pbar:
        time.sleep(0.01)
        if i == 250:
            raise KeyboardInterrupt
except KeyboardInterrupt:
    pbar.close()
    print('\nBarra fechada após interrupção')

# Interrupção em loops aninhados
for i in tqdm(range(5), desc='Externo'):
    try:
        for j in tqdm(range(100), desc='Interno', leave=False):
            time.sleep(0.005)
    except KeyboardInterrupt:
        print(f'\nInterrompido no loop externo {i}')
        raise

# Em processamento paralelo
from tqdm.contrib.concurrent import process_map

def processar(x):
    time.sleep(0.1)
    return x ** 2

try:
    resultados = process_map(processar, range(100), desc='Paralelo')
except KeyboardInterrupt:
    print('\nProcessamento paralelo interrompido')

print('Programa finalizado')

