import click

# Comando básico
@click.command()
def hello():
    """Comando simples que diz olá"""
    click.echo('Hello, World!')

if __name__ == '__main__':
    hello()

# Comando com nome personalizado
@click.command(name='saudacao')
def hello():
    click.echo('Olá!')

# Comando com ajuda personalizada
@click.command(help='Este comando exibe uma mensagem de saudação')
def greet():
    click.echo('Olá, usuário!')

# Comando sem contexto
@click.command(context_settings=dict(help_option_names=['-h', '--help']))
def cli():
    """CLI com opção de ajuda personalizada"""
    click.echo('Executando...')

# Comando com epilog
@click.command(epilog='Exemplo: python script.py --name João')
def cli():
    click.echo('Comando executado')

# Comando com short_help
@click.command(short_help='Comando rápido')
def quick():
    """Descrição longa que aparece no help detalhado"""
    click.echo('Rápido!')

# Comando com no_args_is_help
@click.command(no_args_is_help=True)
def cli():
    click.echo('Este comando requer argumentos')

# Comando com chain (para múltiplos comandos)
@click.command(chain=True)
def cli():
    pass

# Executar comandos
if __name__ == '__main__':
    cli()

import click

# Argumento posicional básico
@click.command()
@click.argument('nome')
def saudacao(nome):
    click.echo(f'Olá, {nome}!')

# Múltiplos argumentos
@click.command()
@click.argument('nome')
@click.argument('idade')
def dados(nome, idade):
    click.echo(f'{nome} tem {idade} anos')

# Argumento com nargs (múltiplos valores)
@click.command()
@click.argument('arquivos', nargs=-1)
def listar(arquivos):
    for arquivo in arquivos:
        click.echo(arquivo)

# Argumento com nargs fixo
@click.command()
@click.argument('coordenadas', nargs=2)
def ponto(coordenadas):
    x, y = coordenadas
    click.echo(f'Ponto: ({x}, {y})')

# Argumento opcional com required=False
@click.command()
@click.argument('arquivo', required=False)
def processar(arquivo):
    if arquivo:
        click.echo(f'Processando {arquivo}')
    else:
        click.echo('Nenhum arquivo especificado')

# Argumento com type
@click.command()
@click.argument('numero', type=int)
def quadrado(numero):
    click.echo(f'{numero}² = {numero ** 2}')

# Argumento com callback
def validar_arquivo(ctx, param, value):
    if not value.endswith('.txt'):
        raise click.BadParameter('Arquivo deve ser .txt')
    return value

@click.command()
@click.argument('arquivo', callback=validar_arquivo)
def ler(arquivo):
    click.echo(f'Lendo {arquivo}')

# Argumento com metavar personalizado
@click.command()
@click.argument('nome', metavar='<USUARIO>')
def saudar(nome):
    click.echo(f'Olá, {nome}')

# Argumento com envvar
@click.command()
@click.argument('token', envvar='API_TOKEN')
def autenticar(token):
