if __name__ == '__main__':
    saudacao()
    dados()
    listar()
    ponto()
    processar()
    quadrado()
    ler()
    saudar()
    autenticar()

import click

# Opção básica
@click.command()
@click.option('--nome')
def saudar(nome):
    click.echo(f'Olá, {nome}')

# Opção com flag booleana
@click.command()
@click.option('--verbose', is_flag=True, help='Modo verboso')
def processar(verbose):
    if verbose:
        click.echo('Modo verboso ativado')
    click.echo('Processando...')

# Opção com múltiplos nomes
@click.command()
@click.option('-n', '--name', '--nome', help='Seu nome')
def saudar(name):
    click.echo(f'Olá, {name}')

# Opção com valor padrão
@click.command()
@click.option('--porta', default=8080, type=int, help='Porta do servidor')
def servidor(porta):
    click.echo(f'Servidor rodando na porta {porta}')

# Opção obrigatória
@click.command()
@click.option('--usuario', required=True, help='Usuário obrigatório')
def login(usuario):
    click.echo(f'Logado como {usuario}')

# Opção com múltiplos valores
@click.command()
@click.option('--cor', multiple=True, help='Cores (pode repetir)')
def pintar(cor):
    click.echo(f'Cores: {", ".join(cor)}')

# Opção com tupla
@click.command()
@click.option('--coordenadas', nargs=2, type=float, help='Coordenadas x y')
def localizar(coordenadas):
    x, y = coordenadas
    click.echo(f'Local: ({x}, {y})')

# Opção com escolhas
@click.command()
@click.option('--modo', type=click.Choice(['rápido', 'lento', 'médio']))
def executar(modo):
    click.echo(f'Modo: {modo}')

# Opção com senha (esconde entrada)
@click.command()
@click.option('--senha', prompt=True, hide_input=True, confirmation_prompt=True)
def configurar(senha):
    click.echo('Senha configurada!')

# Opção com prompt
@click.command()
@click.option('--nome', prompt='Digite seu nome')
def cumprimentar(nome):
    click.echo(f'Olá, {nome}')

# Opção com callback
def validar_idade(ctx, param, value):
    if value < 0 or value > 150:
        raise click.BadParameter('Idade deve estar entre 0 e 150')
    return value

@click.command()
@click.option('--idade', type=int, callback=validar_idade)
def cadastrar(idade):
    click.echo(f'Idade: {idade}')

# Opção com envvar
@click.command()
@click.option('--api-key', envvar='API_KEY', help='Chave da API')
def conectar(api_key):
