import click

# Contexto básico
@click.group()
@click.pass_context
def cli(ctx):
    """CLI principal"""
    ctx.ensure_object(dict)
    ctx.obj['debug'] = False

@cli.command()
@click.pass_context
def info(ctx):
    """Mostra informações"""
    click.echo(f'Debug: {ctx.obj["debug"]}')

# Contexto com dados compartilhados
@click.group()
@click.option('--debug', is_flag=True)
@click.pass_context
def cli_shared(ctx, debug):
    """CLI com contexto compartilhado"""
    ctx.ensure_object(dict)
    ctx.obj['debug'] = debug
    ctx.obj['verbose'] = False

@cli_shared.command()
@click.option('--verbose', is_flag=True)
@click.pass_context
def status(ctx, verbose):
    """Mostra status"""
    ctx.obj['verbose'] = verbose
    click.echo(f'Debug: {ctx.obj["debug"]}')
    click.echo(f'Verbose: {ctx.obj["verbose"]}')

# Contexto com objeto personalizado
class Config:
    def __init__(self):
        self.debug = False
        self.data = {}

@click.group()
@click.pass_context
def cli_config(ctx):
    """CLI com configuração"""
    ctx.obj = Config()

@cli_config.command()
@click.option('--key')
@click.option('--value')
@click.pass_context
def set(ctx, key, value):
    """Define valor"""
    ctx.obj.data[key] = value
    click.echo(f'Definido {key} = {value}')

@cli_config.command()
@click.argument('key')
@click.pass_context
def get(ctx, key):
    """Obtém valor"""
    value = ctx.obj.data.get(key, 'Não encontrado')
    click.echo(f'{key}: {value}')

# Contexto com recursão
@click.command()
@click.option('--level', default=0)
@click.pass_context
def recursivo(ctx, level):
    """Função recursiva com contexto"""
    if level < 3:
        click.echo(f'Nível {level}')
        ctx.invoke(recursivo, level=level+1)

# Contexto com metadados
@click.command()
@click.pass_context
def metadados(ctx):
    """Mostra metadados do contexto"""
    click.echo(f'Comando: {ctx.command.name}')
    click.echo(f'Args: {ctx.args}')
    click.echo(f'Params: {ctx.params}')

if __name__ == '__main__':
    cli()
    cli_shared()
    cli_config()
    recursivo()
    metadados()

