def repeat(intervalo_job):
    """Decorador que agenda a função automaticamente"""
    def decorator(func):
        intervalo_job.do(func)
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            return func(*args, **kwargs)
        return wrapper
    return decorator

