# ============================================
# SOLUÇÃO 4: Decorador genérico safe_schedule
# ============================================

def safe_job(func):
    """Decorador universal para jobs seguros"""
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        try:
            resultado = func(*args, **kwargs)
            logger.info(f'✅ {func.__name__} concluído')
            return resultado
        except Exception as e:
            logger.error(f'❌ {func.__name__} falhou: {e}')
            # Não propaga a exceção - job continua agendado
    return wrapper

