# ============================================
# Wrapper que loga execuções automaticamente
# ============================================

def logged_job(func):
    """Decorador que adiciona logging automático"""
    def wrapper(*args, **kwargs):
        nome = func.__name__
        logger.info(f'⏳ Iniciando: {nome}')
        inicio = time.time()
        try:
            resultado = func(*args, **kwargs)
            duracao = time.time() - inicio
            logger.info(f'✅ Concluído: {nome} ({duracao:.2f}s)')
            return resultado
        except Exception as e:
            duracao = time.time() - inicio
            logger.error(f'❌ Falhou: {nome} ({duracao:.2f}s) - {e}')
    return wrapper

@logged_job
def processar_dados():
    time.sleep(0.5)  # simula processamento
    return 'dados processados'

