# Spider básico
import scrapy

class QuotesSpider(scrapy.Spider):
    name = "quotes"
    start_urls = ["http://quotes.toscrape.com/page/1/"]

    def parse(self, response):
        for quote in response.css("div.quote"):
            yield {
                "text": quote.css("span.text::text").get(),
                "author": quote.css("span small.author::text").get(),
            }

        next_page = response.css("li.next a::attr(href)").get()
        if next_page:
            yield response.follow(next_page, self.parse)

# Spider com argumentos customizados
class ArgSpider(scrapy.Spider):
    name = "argspider"

    def __init__(self, category=None, *args, **kwargs):
        super(ArgSpider, self).__init__(*args, **kwargs)
        self.category = category
        self.start_urls = [f"http://example.com/{category}"]

    def parse(self, response):
        yield {"category": self.category, "title": response.css("title::text").get()}

# Spider com múltiplas regras de parse
class MultiParseSpider(scrapy.Spider):
    name = "multiparse"
    start_urls = ["http://books.toscrape.com/"]

    def parse(self, response):
        for book in response.css("article.product_pod"):
            book_url = book.css("h3 a::attr(href)").get()
            yield response.follow(book_url, self.parse_book)

        next_page = response.css("li.next a::attr(href)").get()
        if next_page:
            yield response.follow(next_page, self.parse)

    def parse_book(self, response):
        yield {
            "title": response.css("h1::text").get(),
            "price": response.css("p.price_color::text").get(),
            "upc": response.css("th:contains('UPC') + td::text").get(),
        }

