from fastapi import FastAPI, Body
from pydantic import BaseModel, Field, field_validator, model_validator
from datetime import datetime

app = FastAPI()

# Exemplo 1: Model básico
class ItemCreate(BaseModel):
    nome: str
    preco: float
    em_estoque: bool = True  # valor padrão

@app.post('/itens')
def criar_item(item: ItemCreate):
    return {'id': 1, **item.model_dump()}

# Exemplo 2: Model com Field() para validações
class Produto(BaseModel):
    nome: str = Field(
        min_length=2,
        max_length=100,
        description='Nome do produto',
        examples=['Notebook Dell']
    )
    preco: float = Field(
        gt=0,
        le=999999.99,
        description='Preço em reais'
    )
    descricao: str | None = Field(
        default=None,
        max_length=500
    )
    tags: list[str] = Field(default_factory=list)

@app.post('/produtos')
def criar_produto(produto: Produto):
    return produto

# Exemplo 3: Models aninhados
class Endereco(BaseModel):
    rua: str
    cidade: str
    estado: str = Field(min_length=2, max_length=2)
    cep: str = Field(pattern=r'^\d{5}-?\d{3}$')

class Usuario(BaseModel):
    nome: str
    email: str
    idade: int = Field(ge=18, le=120)
    endereco: Endereco  # modelo aninhado
    interesses: list[str] = []

@app.post('/usuarios')
def criar_usuario(usuario: Usuario):
    return usuario

# Exemplo 4: Validador customizado
class Pedido(BaseModel):
    produto: str
    quantidade: int = Field(ge=1)
    preco_unitario: float = Field(gt=0)

    @field_validator('produto')
    @classmethod
    def produto_nao_vazio(cls, v):
        if not v.strip():
            raise ValueError('Produto não pode ser vazio')
        return v.strip()

    @model_validator(mode='after')
    def calcular_total(self):
        self.total = self.quantidade * self.preco_unitario
        return self

    total: float = 0

@app.post('/pedidos')
def criar_pedido(pedido: Pedido):
    return pedido

# Exemplo 5: Body com parâmetro singular (não model)
@app.put('/itens/{item_id}')
def atualizar_importancia(
    item_id: int,
    importancia: int = Body(ge=1, le=5)  # valor direto no body
):
    return {'item_id': item_id, 'importancia': importancia}

# Exemplo 6: Múltiplos bodies
@app.post('/transferir')
def transferir(
    origem: Usuario = Body(embed=True),   # embed=True força chave no JSON
    destino: Usuario = Body(embed=True)
):
    return {'origem': origem.nome, 'destino': destino.nome}

# Exemplo 7: Model com exemplo na classe
class ItemExemplo(BaseModel):
    nome: str
    preco: float

    model_config = {
        'json_schema_extra': {
            'examples': [
                {'nome': 'Notebook', 'preco': 4500.00},
                {'nome': 'Mouse', 'preco': 89.90}
            ]
        }
    }

