from fastapi import FastAPI
from pydantic import BaseModel, EmailStr

app = FastAPI()

# === Models separados para entrada e saída ===

class UsuarioCreate(BaseModel):
    nome: str
    email: str
    senha: str  # recebida, nunca retornada

class UsuarioResponse(BaseModel):
    id: int
    nome: str
    email: str
    # senha NÃO está aqui - nunca vai para a resposta

class UsuarioDB(BaseModel):
    id: int
    nome: str
    email: str
    senha_hash: str

# Exemplo 1: response_model filtra campos automaticamente
@app.post('/usuarios', response_model=UsuarioResponse, status_code=201)
def criar_usuario(usuario: UsuarioCreate):
    # Simula salvar no banco com hash da senha
    usuario_db = UsuarioDB(
        id=1,
        nome=usuario.nome,
        email=usuario.email,
        senha_hash='hash_secreto_123'
    )
    return usuario_db  # response_model filtra: só retorna id, nome, email

# Exemplo 2: Lista como response_model
@app.get('/usuarios', response_model=list[UsuarioResponse])
def listar_usuarios():
    return [
        {'id': 1, 'nome': 'Ana', 'email': 'ana@email.com', 'senha_hash': 'xxx'},
        {'id': 2, 'nome': 'Bob', 'email': 'bob@email.com', 'senha_hash': 'yyy'},
    ]

# Exemplo 3: response_model_exclude
class Item(BaseModel):
    nome: str
    preco: float
    descricao: str | None = None
    interno_id: str = 'abc123'

@app.get(
    '/itens/{item_id}',
    response_model=Item,
    response_model_exclude={'interno_id'}  # exclui campo
)
def get_item(item_id: int):
    return Item(nome='Notebook', preco=4500, descricao='Laptop', interno_id='secret')

# Exemplo 4: response_model_exclude_unset
@app.get(
    '/itens/{item_id}/parcial',
    response_model=Item,
    response_model_exclude_unset=True  # omite campos não definidos
)
def get_item_parcial(item_id: int):
    return Item(nome='Mouse', preco=89.90)  # descricao e interno_id omitidos

# Exemplo 5: Múltiplos response models com Union
class MensagemOk(BaseModel):
    mensagem: str
    codigo: int = 200

class MensagemErro(BaseModel):
    erro: str
    codigo: int

@app.get('/status', response_model=MensagemOk | MensagemErro)
def get_status(falhar: bool = False):
    if falhar:
        return MensagemErro(erro='Serviço indisponível', codigo=503)
    return MensagemOk(mensagem='Tudo certo')

