from fastapi import FastAPI, Form, File, UploadFile
from fastapi.responses import HTMLResponse

app = FastAPI()

# Exemplo 1: Form data básico
@app.post('/login')
def login(
    username: str = Form(),
    password: str = Form()
):
    return {'username': username, 'autenticado': True}

# Exemplo 2: Form com validação
@app.post('/cadastro')
def cadastro(
    nome: str = Form(min_length=2, max_length=100),
    email: str = Form(),
    idade: int = Form(ge=18),
    aceita_termos: bool = Form(default=False)
):
    return {'nome': nome, 'email': email, 'idade': idade}

# Exemplo 3: Upload de arquivo com File (bytes)
@app.post('/upload/bytes')
def upload_bytes(
    arquivo: bytes = File(description='Arquivo como bytes')
):
    return {'tamanho': len(arquivo)}

# Exemplo 4: Upload com UploadFile (recomendado para arquivos grandes)
@app.post('/upload')
async def upload_arquivo(arquivo: UploadFile):
    conteudo = await arquivo.read()
    return {
        'nome': arquivo.filename,
        'tipo': arquivo.content_type,
        'tamanho': len(conteudo)
    }

# Exemplo 5: Múltiplos arquivos
@app.post('/upload/multiplos')
async def upload_multiplos(arquivos: list[UploadFile]):
    resultado = []
    for arq in arquivos:
        conteudo = await arq.read()
        resultado.append({
            'nome': arq.filename,
            'tamanho': len(conteudo)
        })
    return resultado

# Exemplo 6: Form + File juntos
@app.post('/post/criar')
async def criar_post(
    titulo: str = Form(),
    conteudo: str = Form(),
    imagem: UploadFile | None = File(default=None)
):
    resultado = {'titulo': titulo, 'conteudo': conteudo}
    if imagem:
        resultado['imagem'] = imagem.filename
    return resultado

# Exemplo 7: Formulário HTML de teste
@app.get('/form', response_class=HTMLResponse)
def form_html():
    return """
    <form action="/upload" method="post" enctype="multipart/form-data">
        <input type="file" name="arquivo">
        <button type="submit">Enviar</button>
    </form>
    """

