from fastapi import FastAPI, Depends, HTTPException, Security
from fastapi.security import (
    OAuth2PasswordBearer,
    OAuth2PasswordRequestForm,
    HTTPBasic, HTTPBasicCredentials,
    APIKeyHeader, APIKeyQuery
)
from pydantic import BaseModel
from datetime import datetime, timedelta
import jwt  # pip install pyjwt

app = FastAPI()

SECRET_KEY = 'minha-chave-secreta-super-segura'
ALGORITHM = 'HS256'

# === OAuth2 com JWT ===

oauth2_scheme = OAuth2PasswordBearer(tokenUrl='token')

class Usuario(BaseModel):
    username: str
    email: str | None = None

# Banco simulado
usuarios_db = {
    'admin': {'username': 'admin', 'email': 'admin@email.com', 'senha': 'admin123'},
}

def criar_token(data: dict, expires_delta: timedelta = timedelta(hours=1)):
    to_encode = data.copy()
    expire = datetime.utcnow() + expires_delta
    to_encode.update({'exp': expire})
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)

def get_usuario_atual(token: str = Depends(oauth2_scheme)):
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        username = payload.get('sub')
        if username is None or username not in usuarios_db:
            raise HTTPException(status_code=401, detail='Token inválido')
        return Usuario(**usuarios_db[username])
    except jwt.ExpiredSignatureError:
        raise HTTPException(status_code=401, detail='Token expirado')
    except jwt.InvalidTokenError:
        raise HTTPException(status_code=401, detail='Token inválido')

# Endpoint de login (gera token)
@app.post('/token')
def login(form_data: OAuth2PasswordRequestForm = Depends()):
    user = usuarios_db.get(form_data.username)
    if not user or user['senha'] != form_data.password:
        raise HTTPException(status_code=401, detail='Credenciais inválidas')
    token = criar_token({'sub': form_data.username})
    return {'access_token': token, 'token_type': 'bearer'}

# Endpoint protegido
@app.get('/perfil', response_model=Usuario)
def perfil(usuario: Usuario = Depends(get_usuario_atual)):
    return usuario

# === API Key ===

api_key_header = APIKeyHeader(name='X-API-Key')

def verificar_api_key(api_key: str = Security(api_key_header)):
    if api_key != 'minha-api-key-secreta':
        raise HTTPException(status_code=403, detail='API key inválida')
    return api_key

@app.get('/dados-api-key')
def dados_protegidos(api_key: str = Depends(verificar_api_key)):
    return {'dados': 'secretos', 'autenticado_via': 'api_key'}

# === HTTP Basic Auth ===

security_basic = HTTPBasic()

@app.get('/basic-auth')
def basic_auth(credentials: HTTPBasicCredentials = Depends(security_basic)):
    if credentials.username != 'admin' or credentials.password != 'senha123':
        raise HTTPException(status_code=401, detail='Credenciais inválidas')
    return {'usuario': credentials.username}

